r\n\r\ntype Props = {\r\n  zone: number;\r\n  text: string;\r\n  title?: string;\r\n  shape?: \"rect\" | \"circle\";\r\n  borderRadius?: number;\r\n  style?: ViewStyle;\r\n  children: React.ReactNode;\r\n  isGlow?: boolean;\r\n  borderColor?: string;\r\n  padding?: PaddingProps;\r\n  margin?: MarginProps;\r\n};\r\n\r\nexport const WalkthroughZone = ({\r\n  zone,\r\n  text,\r\n  title,\r\n  shape = \"rect\",\r\n  borderRadius,\r\n  style,\r\n  children,\r\n  isGlow,\r\n  borderColor = \"white\",\r\n  padding = {},\r\n  margin = {},\r\n}: Props) => {\r\n  const ref = useRef<View>(null);\r\n  const { registerStep, unregisterStep, rootRef } = useWalkthrough();\r\n  const measure = useCallback(() => {\r\n    if (!ref.current || !rootRef.current) return;\r\n    ref.current.measureLayout(\r\n      rootRef.current,\r\n      (x, y, width, height) => {\r\n        if (!width || !height) return;\r\n        registerStep(\r\n          {\r\n            zone,\r\n            text,\r\n            title,\r\n            shape,\r\n            borderRadius,\r\n            isGlow,\r\n            borderColor,\r\n            padding,\r\n            margin,\r\n          },\r\n          { x, y, width, height },\r\n        );\r\n      },\r\n      () => {},\r\n    );\r\n  }, [\r\n    zone,\r\n    text,\r\n    title,\r\n    shape,\r\n    borderRadius,\r\n    isGlow,\r\n    borderColor,\r\n    registerStep,\r\n    rootRef,\r\n    padding,\r\n    margin,\r\n  ]);\r\n  useEffect(() => {\r\n    const id = setTimeout(() => {\r\n      measure();\r\n    }, 500);\r\n    return () => {\r\n      clearTimeout(id);\r\n      unregisterStep(zone);\r\n    };\r\n  }, [measure, zone, unregisterStep]);\r\n  return (\r\n    <View\r\n      ref={ref}\r\n      collapsable={false}\r\n      style={style}\r\n      onLayout={() => {\r\n        measure();\r\n      }}\r\n    >\r\n      {children}\r\n    </View>\r\n  );\r\n};\r\n"]}
